// Branded primitives and discriminated unions shared across modules.
// Principle 1: types beat tests — branded IDs prevent cross-confusion by construction.

import { Brand } from "effect";

export type ScenarioId = string & Brand.Brand<"ScenarioId">;
export type TraceId = string & Brand.Brand<"TraceId">;
export type RunNumber = number & Brand.Brand<"RunNumber">;

export const ScenarioId = Brand.nominal<ScenarioId>();
export const TraceId = Brand.nominal<TraceId>();
export const RunNumber = Brand.nominal<RunNumber>();

// Explicit, named conversion from TraceId to ScenarioId. Used only by the
// trace-scoring path when a Trace omits scenarioId — the trace is synthesized
// into a pseudo-Scenario so the judge can consume it. Naming the conversion
// makes the brand crossing auditable (Principle 1: no silent brand laundering).
export function scenarioIdFromTraceId(t: TraceId): ScenarioId {
  return ScenarioId(t);
}

export type IssueSeverity = "minor" | "significant" | "critical";

export const ISSUE_SEVERITY = {
  Minor: "minor",
  Significant: "significant",
  Critical: "critical",
} as const satisfies { readonly [K in Capitalize<IssueSeverity>]: Uncapitalize<K> };

export type RunSource = "scenario" | "trace";

export const RUN_SOURCE = {
  Scenario: "scenario",
  Trace: "trace",
} as const satisfies { readonly [K in Capitalize<RunSource>]: Uncapitalize<K> };

export type LogLevel = "debug" | "info" | "warn" | "error";

export type RuntimeKind = "docker" | "subprocess";

export const RUNTIME_KIND = {
  Docker: "docker",
  Subprocess: "subprocess",
} as const satisfies { readonly [K in Capitalize<RuntimeKind>]: Uncapitalize<K> };

export interface Issue {
  readonly issue: string;
  readonly severity: IssueSeverity;
}

export interface WorkspaceFile {
  readonly path: string;
  readonly content: string;
}

export interface WorkspaceFileChange {
  readonly path: string;
  readonly before: string | null;
  readonly after: string | null;
}

export interface WorkspaceDiff {
  readonly changed: ReadonlyArray<WorkspaceFileChange>;
}

export interface Turn {
  readonly index: number;
  readonly prompt: string;
  readonly response: string;
  readonly startedAt: string;
  readonly latencyMs: number;
  readonly toolCallCount: number;
  readonly inputTokens: number;
  readonly outputTokens: number;
  readonly cacheReadTokens: number;
  readonly cacheWriteTokens: number;
}

export interface DeterministicCtx {
  readonly transcript: string;
  readonly diff: WorkspaceDiff;
}

// Utility: make unreachable branches a type error. Principle 4.
export function absurd(x: never): never {
  throw new Error(`unreachable: ${JSON.stringify(x)}`);
}

src/emit/observability.ts.source:
// ObservabilityEmitter interface + BraintrustEmitter + PromptfooEmitter.
// Invariant #12: emission never changes verdict or exit code.
// Spec Q-OBS-1 (A): array of emitters, each failure isolated.
// Spec Q-OBS-2 (C): both per-run (streaming) and per-report (roll-up).

import { Effect } from "effect";
import { writeFileSync, mkdirSync } from "node:fs";
import * as path from "node:path";
import { initLogger, type Logger as BraintrustLogger } from "braintrust";
import type { Report, RunRecord } from "../core/schema.js";

export interface ObservabilityEvent {
  readonly record: RunRecord;
}

export interface ObservabilityReport {
  readonly report: Report;
}

export interface ObservabilityEmitter {
  readonly name: string;
  onRun(event: ObservabilityEvent): Effect.Effect<void, never, never>;
  onReport(event: ObservabilityReport): Effect.Effect<void, never, never>;
}

// -------------------- BraintrustEmitter --------------------

export interface BraintrustEmitterOpts {
  readonly project: string;
  readonly apiKey: string;
  readonly experimentName?: string;
}

export class BraintrustEmitter implements ObservabilityEmitter {
  readonly name = "braintrust";
  readonly #opts: BraintrustEmitterOpts;
  #logger: BraintrustLogger<true> | null = null;

  constructor(opts: BraintrustEmitterOpts) {
    this.#opts = opts;
  }

  #ensureLogger(): BraintrustLogger<true> {
    if (this.#logger !== null) return this.#logger;
    this.#logger = initLogger({
      apiKey: this.#opts.apiKey,
      projectName: this.#opts.project,
    });
    return this.#logger;
  }

  onRun(event: ObservabilityEvent): Effect.Effect<void, never, never> {
    return Effect.sync(() => {
      try {
        const logger = this.#ensureLogger();
        logger.log({
          input: { scenarioId: event.record.scenarioId, source: event.record.source },
          output: { pass: event.record.pass, reason: event.record.reason },
          scores: { pass: event.record.pass ? 1 : 0 },
          metadata: {
            runNumber: event.record.runNumber,
            modelName: event.record.modelName,
            judgeModel: event.record.judgeModel,
            latencyMs: event.record.latencyMs,
            retryCount: event.record.retryCount,
            toolCallCount: event.record.toolCallCount,
            inputTokens: event.record.inputTokens,
            outputTokens: event.record.outputTokens,
            overallSeverity: event.record.overallSeverity ?? "none",
          },
        });
      } catch (err) {
        void err;
        // Invariant #12: observability never affects verdict. Drop and move on.
      }
    });
  }

  onReport(_event: ObservabilityReport): Effect.Effect<void, never, never> {
    void _event;
    return Effect.tryPromise({
      try: () => this.#flushLogger(),
      catch: () => null,
    }).pipe(
      Effect.catchAll(() => Effect.void),
      Effect.asVoid,
    );
  }

  #flushLogger() {
    if (this.#logger === null) return Promise.resolve();
    const p = this.#logger.flush();
    return p instanceof Promise ? p : Promise.resolve();
  }
}

// -------------------- PromptfooEmitter --------------------

export interface PromptfooEmitterOpts {
  readonly outputPath: string;
}

export class PromptfooEmitter implements ObservabilityEmitter {
  readonly name = "promptfoo";
  readonly #outputPath: string;

  constructor(opts: PromptfooEmitterOpts) {
    this.#outputPath = opts.outputPath;
  }

  onRun(_event: ObservabilityEvent): Effect.Effect<void, never, never> {
    // Promptfoo's dashboard ingests a single-file results.json (one roll-up
    // per pipeline). We defer to onReport.
    void _event;
    return Effect.void;
  }

  onReport(event: ObservabilityReport): Effect.Effect<void, never, never> {
    return Effect.sync(() => {
      try {
        const payload = toPromptfooResults(event.report);
        const abs = path.resolve(this.#outputPath);
        mkdirSync(path.dirname(abs), { recursive: true });
        writeFileSync(abs, JSON.stringify(payload, null, 2), "utf8");
      } catch (err) {
        void err;
        // Invariant #12.
      }
    });
  }
}

interface PromptfooResultRow {
  readonly promptId: string;
  readonly testIdx: number;
  readonly success: boolean;
  readonly score: number;
  readonly latencyMs: number;
  readonly response: {
    readonly output: string;
    readonly tokenUsage: { readonly prompt: number; readonly completion: number; readonly cached: number };
  };
  readonly gradingResult: { readonly pass: boolean; readonly score: number; readonly reason: string };
  readonly vars: Readonly<Record<string, string | number | boolean>>;
}

function toPromptfooResults(report: Report): {
  readonly version: 3;
  readonly createdAt: string;
  readonly results: {
    readonly timestamp: string;
    readonly results: ReadonlyArray<PromptfooResultRow>;
    readonly stats: {
      readonly successes: number;
      readonly failures: number;
      readonly tokenUsage: { readonly total: number; readonly prompt: number; readonly completion: number };
    };
  };
} {
  const now = new Date().toISOString();
  const rows: PromptfooResultRow[] = report.runs.map((r, i) => ({
    promptId: r.scenarioId,
    testIdx: i,
    success: r.pass,
    score: r.pass ? 1 : 0,
    latencyMs: r.latencyMs,
    response: {
      output: r.reason,
      tokenUsage: {
        prompt: r.inputTokens,
        completion: r.outputTokens,
        cached: r.cacheReadTokens,
      },
    },
    gradingResult: { pass: r.pass, score: r.pass ? 1 : 0, reason: r.reason },
    vars: {
      scenarioId: r.scenarioId,
      runNumber: r.runNumber,
      source: r.source,
    },
  }));
  let totalPrompt = 0;
  let totalCompletion = 0;
  for (const r of report.runs) {
    totalPrompt += r.inputTokens;
    totalCompletion += r.outputTokens;
  }
  return {
    version: 3,
    createdAt: now,
    results: {
      timestamp: now,
      results: rows,
      stats: {
        successes: report.summary.passed,
        failures: report.summary.failed,
        tokenUsage: {
          total: totalPrompt + totalCompletion,
          prompt: totalPrompt,
          completion: totalCompletion,
        },
      },
    },
  };
}

src/emit/report.ts.source:
// Report emitter: writes the summary.md + results.jsonl + details/*.yaml triple,
// and optionally posts a GitHub comment.
// Invariant #12: emission never changes verdicts. Every filesystem failure is
// swallowed on the hot path so a disk blip doesn't flip run outcomes.

import { Effect } from "effect";
import { Value } from "@sinclair/typebox/value";
import { mkdirSync, appendFileSync, writeFileSync, existsSync, unlinkSync, readFileSync } from "node:fs";
import { execFileSync } from "node:child_process";
import * as path from "node:path";
import * as YAML from "yaml";
import { PublishError } from "../core/errors.js";
import { RunRecordSchema, type Report, type RunRecord } from "../core/schema.js";
import { ScenarioId, TraceId, RunNumber } from "../core/types.js";

export interface ReportEmitterOpts {
  readonly resultsDir: string;
  readonly githubComment?: number;
  readonly githubCommentArtifactUrl?: string;
}

export interface ReportEmitter {
  emitRun(record: RunRecord): Effect.Effect<void, never, never>;
  emitReport(report: Report): Effect.Effect<void, never, never>;
  publishGithubComment(report: Report): Effect.Effect<void, PublishError, never>;
}

const GITHUB_COMMENT_BODY_LIMIT = 65_000;

function ensureDir(dir: string): void {
  mkdirSync(dir, { recursive: true });
}

function runFilename(record: RunRecord): string {
  const safeId = record.scenarioId.replace(/[^A-Za-z0-9_-]/gu, "_");
  return `${safeId}.${String(record.runNumber)}.yaml`;
}

function renderSummary(report: Report): string {
  const { summary } = report;
  const lines: string[] = [];
  lines.push("# cc-judge report");
  lines.push("");
  lines.push(`- total: ${String(summary.total)}`);
  lines.push(`- passed: ${String(summary.passed)}`);
  lines.push(`- failed: ${String(summary.failed)}`);
  lines.push(`- avg latency: ${summary.avgLatencyMs.toFixed(0)}ms`);
  if (report.artifactsDir !== undefined) {
    lines.push(`- artifacts: ${report.artifactsDir}`);
  }
  lines.push("");
  lines.push("## Runs");
  lines.push("");
  lines.push("| scenario | run | verdict | severity | latency | retries |");
  lines.push("| --- | --- | --- | --- | --- | --- |");
  for (const r of report.runs) {
    const verdict = r.pass ? "PASS" : "FAIL";
    const severity = r.overallSeverity ?? "-";
    lines.push(
      `| ${r.scenarioId} | ${String(r.runNumber)} | ${verdict} | ${severity} | ${String(r.latencyMs)}ms | ${String(r.retryCount)} |`,
    );
  }
  lines.push("");
  lines.push("## Failures");
  lines.push("");
  const failures = report.runs.filter((r) => !r.pass);
  if (failures.length === 0) {
    lines.push("None.");
  } else {
    for (const r of failures) {
      lines.push(`### ${r.scenarioId} #${String(r.runNumber)}`);
      lines.push(`- reason: ${r.reason}`);
      if (r.issues.length > 0) {
        lines.push("- issues:");
        for (const i of r.issues) {
          lines.push(`  - [${i.severity}] ${i.issue}`);
        }
      }
      lines.push("");
    }
  }
  return lines.join("\n");
}

function truncateForGitHub(body: string, artifactUrl: string | undefined): string {
  if (body.length <= GITHUB_COMMENT_BODY_LIMIT) return body;
  const prefix = body.slice(0, GITHUB_COMMENT_BODY_LIMIT - 500);
  const suffix = artifactUrl !== undefined
    ? `\n\n…truncated. Full report: ${artifactUrl}`
    : "\n\n…truncated (raise --github-comment-artifact-url to link the full report).";
  return prefix + suffix;
}

function ghAvailable(): boolean {
  try {
    execFileSync("gh", ["--version"], { stdio: "ignore" });
    return true;
  } catch (err) {
    void err;
    return false;
  }
}

function postGithubComment(prNumber: number, body: string): Effect.Effect<void, PublishError, never> {
  return Effect.suspend(() => {
    if (!ghAvailable()) {
      return Effect.fail(new PublishError({ cause: { _tag: "GhCliMissing" } }));
    }
    return Effect.tryPromise({
      try: () => runGh(prNumber, body),
      catch: (err) =>
        new PublishError({
          cause: {
            _tag: "GhCliFailed",
            exitCode: 1,
            stderr: err instanceof Error ? err.message : String(err),
          },
        }),
    });
  });
}

function runGh(prNumber: number, body: string) {
  return new Promise<void>((resolve, reject) => {
    try {
      execFileSync("gh", ["pr", "comment", String(prNumber), "--body-file", "-"], {
        input: body,
        stdio: ["pipe", "ignore", "pipe"],
      });
      resolve();
    } catch (err) {
      reject(err instanceof Error ? err : new Error(String(err)));
    }
  });
}

export function makeReportEmitter(opts: ReportEmitterOpts): ReportEmitter {
  const resultsDir = path.resolve(opts.resultsDir);
  const detailsDir = path.join(resultsDir, "details");
  const jsonlPath = path.join(resultsDir, "results.jsonl");
  const summaryPath = path.join(resultsDir, "summary.md");

  return {
    emitRun(record) {
      return Effect.sync(() => {
        try {
          ensureDir(detailsDir);
          appendFileSync(jsonlPath, `${JSON.stringify(record)}\n`, "utf8");
          const yamlPath = path.join(detailsDir, runFilename(record));
          writeFileSync(yamlPath, YAML.stringify(record), "utf8");
        } catch (err) {
          void err;
          // Emission is non-verdict. Drop and move on (invariant #12).
        }
      });
    },

    emitReport(report) {
      return Effect.sync(() => {
        try {
          ensureDir(resultsDir);
          // Rewrite results.jsonl from the finalized record list. The streaming
          // emitRun path is best-effort; the report is the canonical form.
          if (existsSync(jsonlPath)) unlinkSync(jsonlPath);
          const jsonl = report.runs.map((r) => JSON.stringify(r)).join("\n");
          writeFileSync(jsonlPath, jsonl.length > 0 ? `${jsonl}\n` : "", "utf8");
          writeFileSync(summaryPath, renderSummary(report), "utf8");
          ensureDir(detailsDir);
          for (const r of report.runs) {
            writeFileSync(path.join(detailsDir, runFilename(r)), YAML.stringify(r), "utf8");
          }
        } catch (err) {
          void err;
          // See emitRun comment. Verdict data is already in Report; disk is secondary.
        }
      });
    },

    publishGithubComment(report) {
      const prNumber = opts.githubComment;
      if (prNumber === undefined) return Effect.void;
      const body = truncateForGitHub(renderSummary(report), opts.githubCommentArtifactUrl);
      return postGithubComment(prNumber, body);
    },
  };
}

// Helper: read an existing jsonl back into RunRecord[]. Used by scoring CLI
// to resume from partial output when run with --continue.
export function readRunsJsonl(resultsDir: string): ReadonlyArray<RunRecord> {
  const jsonlPath = path.join(path.resolve(resultsDir), "results.jsonl");
  if (!existsSync(jsonlPath)) return [];
  const raw = readFileSync(jsonlPath, "utf8");
  const out: RunRecord[] = [];
  for (const line of raw.split("\n")) {
    const trimmed = line.trim();
    if (trimmed.length === 0) continue;
    let parsed: unknown;
    try {
      parsed = JSON.parse(trimmed);
    } catch (err) {
      void err;
      // Skip malformed line; inflight-crash recovery is best-effort.
      continue;
    }
    if (!Value.Check(RunRecordSchema, parsed)) continue;
    const decoded = Value.Decode(RunRecordSchema, parsed);
    const { scenarioId: rawScenarioId, traceId: rawTraceId, runNumber: rawRunNumber, ...rest } = decoded;
    const record: RunRecord = {
      ...rest,
      scenarioId: ScenarioId(rawScenarioId),
      runNumber: RunNumber(rawRunNumber),
      ...(rawTraceId !== undefined ? { traceId: TraceId(rawTraceId) } : {}),
    };
    out.push(record);
  }
  return out;
}

src/emit/trace-adapter.ts.source:
// Trace format adapters: convert external trace formats into the canonical cc-judge Trace.
// Spec Q-ONLINE-1 (A): canonical Trace + adapters. OTel adapter shipped in v1.
// Invariant #6: unparseable traces fold into a critical-severity RunRecord upstream;
// at this layer we only fail with TraceDecodeError.

import { Effect } from "effect";
import { Value } from "@sinclair/typebox/value";
import * as YAML from "yaml";
import { TraceDecodeError } from "../core/errors.js";
import { TraceSchema, type Trace } from "../core/schema.js";
import { TraceId, ScenarioId, type Turn } from "../core/types.js";

export type TraceFormat = "canonical" | "otel";

export const TRACE_FORMAT = {
  Canonical: "canonical",
  Otel: "otel",
} as const satisfies { readonly [K in Capitalize<TraceFormat>]: Uncapitalize<K> };

export interface TraceAdapter {
  readonly format: TraceFormat;
  decode(source: string, originPath: string): Effect.Effect<Trace, TraceDecodeError, never>;
}

// -------------------- canonical --------------------
// Accepts either YAML or JSON matching TraceSchema. The loader picks a format
// by extension; here we try JSON first then YAML.

function parseEither(source: string): unknown {
  const trimmed = source.trimStart();
  if (trimmed.startsWith("{") || trimmed.startsWith("[")) {
    return JSON.parse(source);
  }
  return YAML.parse(source);
}

function decodeCanonical(source: string, originPath: string): Effect.Effect<Trace, TraceDecodeError, never> {
  return Effect.suspend(() => {
    let parsed: unknown;
    try {
      parsed = parseEither(source);
    } catch (err) {
      return Effect.fail(
        new TraceDecodeError({
          cause: {
            _tag: "SchemaInvalid",
            path: originPath,
            errors: [err instanceof Error ? err.message : String(err)],
          },
        }),
      );
    }
    const errs: string[] = [];
    for (const e of Value.Errors(TraceSchema, parsed)) {
      errs.push(`${e.path} ${e.message}`);
    }
    if (errs.length > 0) {
      return Effect.fail(
        new TraceDecodeError({ cause: { _tag: "SchemaInvalid", path: originPath, errors: errs } }),
      );
    }
    const decoded = Value.Decode(TraceSchema, parsed);
    const { scenarioId: rawScenarioId, traceId: rawTraceId, ...rest } = decoded;
    const base: Trace = {
      ...rest,
      traceId: TraceId(rawTraceId),
    };
    const trace: Trace = rawScenarioId !== undefined
      ? { ...base, scenarioId: ScenarioId(rawScenarioId) }
      : base;
    return Effect.succeed(trace);
  });
}

export const canonicalTraceAdapter: TraceAdapter = {
  format: TRACE_FORMAT.Canonical,
  decode: decodeCanonical,
};

// -------------------- otel --------------------
// Minimal OTel → canonical: each LLM span becomes a Turn. We accept the
// "resourceSpans" envelope emitted by the OpenTelemetry JSON exporter and
// look for spans with `gen_ai.system` attributes. Anything unrecognized fails
// SchemaInvalid — upstream folds it into a critical RunRecord.

interface OtelKeyValue {
  readonly key?: unknown;
  readonly value?: unknown;
}

interface OtelSpan {
  readonly name?: unknown;
  readonly startTimeUnixNano?: unknown;
  readonly endTimeUnixNano?: unknown;
  readonly attributes?: unknown;
}

interface OtelEnvelope {
  readonly resourceSpans?: unknown;
}

function attrString(attrs: ReadonlyArray<OtelKeyValue>, key: string): string | undefined {
  for (const kv of attrs) {
    if (kv.key === key) {
      const v = kv.value;
      if (typeof v === "object" && v !== null) {
        const inner: { stringValue?: unknown } = v;
        if (typeof inner.stringValue === "string") return inner.stringValue;
      }
    }
  }
  return undefined;
}

function attrNumber(attrs: ReadonlyArray<OtelKeyValue>, key: string): number | undefined {
  for (const kv of attrs) {
    if (kv.key === key) {
      const v = kv.value;
      if (typeof v === "object" && v !== null) {
        const inner: { intValue?: unknown; doubleValue?: unknown } = v;
        if (typeof inner.intValue === "number") return inner.intValue;
        if (typeof inner.intValue === "string") {
          const n = Number(inner.intValue);
          if (!Number.isNaN(n)) return n;
        }
        if (typeof inner.doubleValue === "number") return inner.doubleValue;
      }
    }
  }
  return undefined;
}

function spansFromEnvelope(env: OtelEnvelope): ReadonlyArray<OtelSpan> {
  const out: OtelSpan[] = [];
  const resourceSpans = env.resourceSpans;
  if (!Array.isArray(resourceSpans)) return out;
  for (const rs of resourceSpans) {
    if (typeof rs !== "object" || rs === null) continue;
    const scopeSpans = (rs as { scopeSpans?: unknown }).scopeSpans;
    if (!Array.isArray(scopeSpans)) continue;
    for (const ss of scopeSpans) {
      if (typeof ss !== "object" || ss === null) continue;
      const spans = (ss as { spans?: unknown }).spans;
      if (!Array.isArray(spans)) continue;
      for (const s of spans) {
        if (typeof s === "object" && s !== null) out.push(s);
      }
    }
  }
  return out;
}

function toTurn(span: OtelSpan, index: number): Turn | null {
  const attrs: ReadonlyArray<OtelKeyValue> = Array.isArray(span.attributes) ? span.attributes : [];
  const prompt = attrString(attrs, "gen_ai.prompt") ?? attrString(attrs, "input") ?? "";
  const response = attrString(attrs, "gen_ai.completion") ?? attrString(attrs, "output") ?? "";
  if (prompt === "" && response === "") return null;
  const startNs = typeof span.startTimeUnixNano === "string" ? Number(span.startTimeUnixNano) : 0;
  const endNs = typeof span.endTimeUnixNano === "string" ? Number(span.endTimeUnixNano) : startNs;
  const latencyMs = Math.max(0, Math.round((endNs - startNs) / 1_000_000));
  return {
    index,
    prompt,
    response,
    startedAt: startNs > 0 ? new Date(startNs / 1_000_000).toISOString() : new Date().toISOString(),
    latencyMs,
    toolCallCount: attrNumber(attrs, "gen_ai.tool_call_count") ?? 0,
    inputTokens: attrNumber(attrs, "gen_ai.usage.input_tokens") ?? 0,
    outputTokens: attrNumber(attrs, "gen_ai.usage.output_tokens") ?? 0,
    cacheReadTokens: attrNumber(attrs, "gen_ai.usage.cache_read_input_tokens") ?? 0,
    cacheWriteTokens: attrNumber(attrs, "gen_ai.usage.cache_creation_input_tokens") ?? 0,
  };
}

function decodeOtel(source: string, originPath: string): Effect.Effect<Trace, TraceDecodeError, never> {
  return Effect.suspend(() => {
    let parsed: unknown;
    try {
      parsed = JSON.parse(source);
    } catch (err) {
      return Effect.fail(
        new TraceDecodeError({
          cause: {
            _tag: "SchemaInvalid",
            path: originPath,
            errors: [err instanceof Error ? err.message : String(err)],
          },
        }),
      );
    }
    if (typeof parsed !== "object" || parsed === null) {
      return Effect.fail(
        new TraceDecodeError({
          cause: { _tag: "SchemaInvalid", path: originPath, errors: ["root is not an object"] },
        }),
      );
    }
    const envelope: OtelEnvelope = parsed;
    const spans = spansFromEnvelope(envelope);
    const turns: Turn[] = [];
    for (const s of spans) {
      const t = toTurn(s, turns.length);
      if (t !== null) turns.push(t);
    }
    if (turns.length === 0) {
      return Effect.fail(
        new TraceDecodeError({
          cause: { _tag: "SchemaInvalid", path: originPath, errors: ["no LLM spans found"] },
        }),
      );
    }
    const trace: Trace = {
      traceId: TraceId(originPath),
      name: originPath,
      turns,
      expectedBehavior: "",
      validationChecks: [],
    };
    return Effect.succeed(trace);
  });
}

export const otelTraceAdapter: TraceAdapter = {
  format: TRACE_FORMAT.Otel,
  decode: decodeOtel,
};

export function getTraceAdapter(format: TraceFormat): TraceAdapter {
  switch (format) {
    case TRACE_FORMAT.Canonical:
      return canonicalTraceAdapter;
    case TRACE_FORMAT.Otel:
      return otelTraceAdapter;
  }
}

